import React, { useEffect, useState } from "react";
import { supabase } from "../supabaseClient";
import { 
  LogOut, RefreshCcw, MapPin, Clock, Phone, 
  Smartphone, Car, Navigation, CheckCircle, 
  XCircle, Send, Calendar, Activity, Loader2
} from "lucide-react";

const Dashboard = ({ session }) => {
  const [rides, setRides] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState("all");

  useEffect(() => {
    fetchRides();
    // Real-time updates for any DB change
    const subscription = supabase
      .channel('rides-admin')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'rides' }, () => fetchRides())
      .subscribe();

    return () => supabase.removeChannel(subscription);
  }, []);

  const fetchRides = async () => {
    const { data, error } = await supabase
      .from("rides")
      .select("*")
      .order("created_at", { ascending: false });

    if (!error) setRides(data);
    setLoading(false);
  };

  const updateStatus = async (id, newStatus) => {
    await supabase.from('rides').update({ status: newStatus }).eq('id', id);
    fetchRides();
  };

  // --- Dynamic Stats Calculation ---
  const todayDate = new Date().toISOString().split('T')[0];
  const stats = {
    total: rides.length,
    pending: rides.filter(r => r.status === 'pending').length,
    today: rides.filter(r => r.ride_date === todayDate).length,
    completed: rides.filter(r => r.status === 'completed').length
  };

  const filteredData = filter === "all" ? rides : rides.filter(r => r.status === filter);

  // --- Premium Styles ---
  const styles = {
    container: { minHeight: "100vh", background: "#fdf2f5", padding: "30px", fontFamily: "'Inter', sans-serif" },
    grid: { display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(240px, 1fr))", gap: "20px", marginBottom: "30px" },
    statCard: (color) => ({
      background: "#fff", padding: "24px", borderRadius: "20px", borderLeft: `6px solid ${color}`,
      boxShadow: "0 10px 25px rgba(229, 90, 123, 0.08)", display: "flex", justifyContent: "space-between", alignItems: "center"
    }),
    tableCard: { background: "#fff", borderRadius: "24px", padding: "25px", boxShadow: "0 10px 30px rgba(0,0,0,0.02)", border: "1px solid rgba(229, 90, 123, 0.1)" },
    badge: (status) => {
      const colors = { pending: "#f59e0b", confirmed: "#3b82f6", completed: "#10b981", cancelled: "#ef4444" };
      return { background: `${colors[status]}15`, color: colors[status], padding: "6px 14px", borderRadius: "10px", fontSize: "12px", fontWeight: "700", textTransform: "uppercase" };
    }
  };

  if (loading) return <div style={{ display: "flex", height: "100vh", alignItems: "center", justifyContent: "center" }}><Loader2 className="spin" size={40} color="#e55a7b" /></div>;

  return (
    <div style={styles.container}>
      {/* Header Section */}
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "30px" }}>
        <div>
          <h1 style={{ margin: 0, color: "#2d3436", fontSize: "28px" }}>PAHEL Command Center</h1>
          <p style={{ color: "#636e72", margin: "5px 0 0" }}>Monitoring real-time mobility requests</p>
        </div>
        <button onClick={() => supabase.auth.signOut()} style={{ background: "#fff", border: "1px solid #eee", padding: "10px 20px", borderRadius: "12px", cursor: "pointer", display: "flex", alignItems: "center", gap: "10px", fontWeight: "600" }}>
          <LogOut size={18} /> Logout
        </button>
      </div>

      {/* Stats Section */}
      <div style={styles.grid}>
        <div style={styles.statCard("#e55a7b")}>
          <div><p style={{ margin: 0, color: "#636e72" }}>Total Bookings</p><h2 style={{ margin: "5px 0" }}>{stats.total}</h2></div>
          <Activity color="#e55a7b" size={32} opacity={0.3} />
        </div>
        <div style={styles.statCard("#f59e0b")}>
          <div><p style={{ margin: 0, color: "#636e72" }}>Pending Actions</p><h2 style={{ margin: "5px 0" }}>{stats.pending}</h2></div>
          <Clock color="#f59e0b" size={32} opacity={0.3} />
        </div>
        <div style={styles.statCard("#3b82f6")}>
          <div><p style={{ margin: 0, color: "#636e72" }}>Today's Rides</p><h2 style={{ margin: "5px 0" }}>{stats.today}</h2></div>
          <Calendar color="#3b82f6" size={32} opacity={0.3} />
        </div>
        <div style={styles.statCard("#10b981")}>
          <div><p style={{ margin: 0, color: "#636e72" }}>Completed</p><h2 style={{ margin: "5px 0" }}>{stats.completed}</h2></div>
          <CheckCircle color="#10b981" size={32} opacity={0.3} />
        </div>
      </div>

      {/* Main Table Section */}
      <div style={styles.tableCard}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "25px" }}>
          <div style={{ display: "flex", gap: "12px", background: "#fdf2f5", padding: "6px", borderRadius: "14px" }}>
            {['all', 'pending', 'confirmed', 'completed'].map(m => (
              <button key={m} onClick={() => setFilter(m)} style={{ padding: "8px 20px", borderRadius: "10px", border: "none", background: filter === m ? "#e55a7b" : "transparent", color: filter === m ? "#fff" : "#e55a7b", cursor: "pointer", fontWeight: "600", textTransform: "capitalize" }}>{m}</button>
            ))}
          </div>
          <button onClick={fetchRides} style={{ background: "#fff", border: "1px solid #eee", padding: "10px", borderRadius: "12px", cursor: "pointer" }}>
            <RefreshCcw size={20} color="#e55a7b" />
          </button>
        </div>

        <div style={{ overflowX: "auto" }}>
          <table style={{ width: "100%", borderCollapse: "collapse" }}>
            <thead>
              <tr style={{ textAlign: "left", borderBottom: "2px solid #fdf2f5" }}>
                <th style={{ padding: "15px", color: "#636e72" }}>Passenger Details</th>
                <th style={{ padding: "15px", color: "#636e72" }}>Route & Map</th>
                <th style={{ padding: "15px", color: "#636e72" }}>Status</th>
                <th style={{ padding: "15px", color: "#636e72" }}>Quick Actions</th>
              </tr>
            </thead>
            <tbody>
              {filteredData.map(ride => (
                <tr key={ride.id} style={{ borderBottom: "1px solid #f9f9f9", transition: "0.2s" }}>
                  <td style={{ padding: "15px" }}>
                    <div style={{ fontWeight: "700" }}>{ride.passenger_name}</div>
                    <div style={{ fontSize: "12px", color: "#636e72" }}><Phone size={12} /> {ride.phone_number}</div>
                    {ride.alt_phone && <div style={{ fontSize: "12px", color: "#b2bec3" }}><Smartphone size={12} /> {ride.alt_phone}</div>}
                  </td>
                  <td style={{ padding: "15px" }}>
                    <div style={{ fontSize: "13px", color: "#27ae60", fontWeight: "500" }}><MapPin size={12}/> {ride.pickup_location}</div>
                    <div style={{ fontSize: "13px", color: "#e74c3c", marginTop: "5px" }}><Navigation size={12}/> {ride.drop_location}</div>
                  </td>
                  <td style={{ padding: "15px" }}>
                    <span style={styles.badge(ride.status)}>{ride.status}</span>
                  </td>
                  <td style={{ padding: "15px" }}>
                    <div style={{ display: "flex", gap: "10px" }}>
                      <button onClick={() => updateStatus(ride.id, 'confirmed')} style={{ border: "1px solid #3b82f630", background: "#3b82f610", color: "#3b82f6", padding: "8px", borderRadius: "10px", cursor: "pointer" }}><Send size={16} /></button>
                      <button onClick={() => updateStatus(ride.id, 'completed')} style={{ border: "1px solid #10b98130", background: "#10b98110", color: "#10b981", padding: "8px", borderRadius: "10px", cursor: "pointer" }}><CheckCircle size={16} /></button>
                      <button onClick={() => updateStatus(ride.id, 'cancelled')} style={{ border: "1px solid #ef444430", background: "#ef444410", color: "#ef4444", padding: "8px", borderRadius: "10px", cursor: "pointer" }}><XCircle size={16} /></button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
      <style>{`.spin { animation: rotate 1s linear infinite; } @keyframes rotate { 100% { transform: rotate(360deg); } }`}</style>
    </div>
  );
};

export default Dashboard;
